**Prices re-fetched on every `/list` mount** (`list-page.js:272`)

No caching between navigations means `/data/prices.json` is fetched fresh each time the user navigates away and back.

```js
// BEFORE (list-page.js)
async function _loadPrices() {
  const res = await fetch('/data/prices.json');
  return res.json();
}

// AFTER — module-level cache with 1-hour TTL
let _pricesCache = null;
let _pricesFetchedAt = 0;

async function _loadPrices() {
  if (_pricesCache && Date.now() - _pricesFetchedAt < 3_600_000) {
    return _pricesCache;
  }
  const res = await fetch('/data/prices.json');
  _pricesCache = await res.json();
  _pricesFetchedAt = Date.now();
  return _pricesCache;
}
```

**Cookie parsed on every `getItemSync()` call** (`storage-manager.js:514-532`)

`document.cookie` is split and scanned linearly each time — called multiple times during startup hydration.

```js
// BEFORE
_getCookie(key) {
  const cookies = document.cookie.split('; ');
  return cookies.find(c => c.startsWith(key + '='))?.split('=')[1];
}

// AFTER — parse once, invalidate on write
let _cookieCache = null;
function _parseCookies() {
  _cookieCache = Object.fromEntries(
    document.cookie.split('; ').filter(Boolean).map(c => c.split('='))
  );
}
_getCookie(key) {
  if (!_cookieCache) _parseCookies();
  return _cookieCache[key];
}
_setCookie(key, value, ...) {
  _cookieCache = null; // invalidate on write
  // ...existing cookie write logic
}
```

---

**Path selector re-parsed on every `.get()` call** (`state-manager.js:600-602`)

```js
// BEFORE
get(path) {
  return path.split('.').reduce((obj, key) => obj?.[key], this._state);
}

// AFTER — memoize compiled path accessors
const _pathCache = new Map();
get(path) {
  if (!_pathCache.has(path)) {
    const keys = path.split('.');
    _pathCache.set(path, state => keys.reduce((obj, k) => obj?.[k], state));
  }
  return _pathCache.get(path)(this._state);
}
```

**Double async hydration triggers subscribers twice** (`state-manager.js:905-927`)

Sync localStorage read fires subscribers, then IndexedDB read fires them again ~10ms later. Add a hydration flag:

```js
async _hydrate() {
  this._hydrating = true;
  const syncData = this._storage.getItemSync('state');
  if (syncData) this._applyHydration(syncData);

  const asyncData = await this._storage.getItem('state');
  if (asyncData) this._applyHydration(asyncData); // merge on top, don't re-trigger

  this._hydrating = false;
  this._notifySubscribers('*'); // single notification after both reads
}

dispatch(action) {
  // ...existing logic
  if (!this._hydrating) this._notifySubscribers(changedPaths);
}
```

---

**Fuse.js loaded eagerly but only used on `/list`** (`vite.config.js`)

Fuse.js adds ~50KB gzipped to the main bundle. Dynamic import defers it until the search field is first focused:

```js
// list-page.js — lazy-load Fuse only when search is first used
let _fuse = null;
async function _getSearchEngine(supplements) {
  if (!_fuse) {
    const { default: Fuse } = await import('fuse.js');
    _fuse = new Fuse(supplements, { keys: ['name', 'category'], threshold: 0.3 });
  }
  return _fuse;
}

searchInput.addEventListener('focus', () => _getSearchEngine(supplements), { once: true });
```

**ExcelJS always loaded even when user never exports** (`vite.config.js:84`)

Remove it from `build.rollupOptions.input`; lazy-import in the settings page only:

```js
// settings-page.js
async function _exportToExcel(data) {
  const { default: ExcelJS } = await import('exceljs');
  const wb = new ExcelJS.Workbook();
  // ...existing export logic
}
```

---

**Analytics engine registers wildcard listener, never cleans up** (`analytics-engine.js:84`)

Every state change triggers activity recording with no debounce and no `off()` path:

```js
// BEFORE — fires on every state change
eventBus.on('*', event => this._recordActivity(event));

// AFTER — debounced + cleanup
const _debouncedRecord = debounce(event => this._recordActivity(event), 500);
const _unsubscribe = eventBus.on('*', _debouncedRecord);

destroy() {
  _unsubscribe();
}
```

**300+ individual card event listeners instead of delegation** (list-page.js)

Each rendered supplement card attaches its own click listener. With 300 supplements visible, that's 300+ listeners:

```js
// BEFORE — listener per card
supplements.forEach(s => {
  const card = renderCard(s);
  card.addEventListener('click', () => openModal(s.id));
  grid.appendChild(card);
});

// AFTER — single delegated listener on grid
grid.addEventListener('click', e => {
  const card = e.target.closest('[data-supplement-id]');
  if (card) openModal(card.dataset.supplementId);
});
```

---

| Item | Current | Fix | Savings |
|------|---------|-----|---------|
| Fuse.js in main bundle | ~50KB gz | Dynamic import | ~50KB on all non-list routes |
| ExcelJS always bundled | ~200KB | Lazy import on settings | ~200KB on all non-settings routes |
| VirtualScroller uses `top` | Layout recalc | Use `transform: translateY()` | Eliminates reflows on scroll |

**VirtualScroller positioning fix** (`virtual-scroller.js:148-157`):
```js
// BEFORE — triggers layout
item.style.top = `${offset}px`;
item.style.position = 'absolute';

// AFTER — compositor-only, no layout
item.style.transform = `translateY(${offset}px)`;
item.style.position = 'absolute';
item.style.top = '0';
item.style.willChange = 'transform';
```

